import type * as DMMF from '@prisma/dmmf'

function mapScalarType(dmmfType: string): string {
  switch (dmmfType) {
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'Int':
    case 'Float':
    case 'Decimal':
    case 'BigInt':
      return 'number'
    case 'DateTime':
      return 'string'
    case 'Json':
      return 'unknown'
    case 'Bytes':
      return 'string'
    default:
      return 'unknown'
  }
}

/** Maps a DMMF field to its TypeScript type for use in model interfaces (includes relations). */
function mapFieldToInterfaceType(field: DMMF.Field): string {
  let base: string
  if (field.kind === 'scalar') {
    base = mapScalarType(field.type)
  } else if (field.kind === 'enum') {
    base = field.type
  } else {
    base = field.type
  }

  const withList = field.isList ? `${base}[]` : base
  return field.isRequired ? withList : `${withList} | null`
}

/** Maps a DMMF field to its TypeScript type for use in input types (scalar and enum only). */
function mapFieldToInputType(field: DMMF.Field): string {
  if (field.kind === 'scalar') {
    const base = mapScalarType(field.type)
    return field.isList ? `${base}[]` : base
  }
  if (field.kind === 'enum') {
    return field.isList ? `${field.type}[]` : field.type
  }
  return 'unknown'
}

function isAutoGenerated(field: DMMF.Field): boolean {
  return (field.isId === true && field.hasDefaultValue) || field.isGenerated === true
}

function isExcludedFromCreate(field: DMMF.Field): boolean {
  return field.kind === 'object' || field.isReadOnly || isAutoGenerated(field) || field.isUpdatedAt === true
}

function isExcludedFromUpdate(field: DMMF.Field): boolean {
  return field.kind === 'object' || field.isReadOnly || field.isId || field.isUpdatedAt === true
}

/**
 * Returns the primary field used to identify a record in URL path segments.
 * Prefers `@id`, falls back to the first scalar `@unique` field.
 */
function findPrimaryField(model: DMMF.Model): DMMF.Field | undefined {
  return model.fields.find((f) => f.isId) ?? model.fields.find((f) => f.isUnique && f.kind === 'scalar')
}

/** Renders a DMMF enum as a TypeScript union type. */
export function renderEnum(dmmfEnum: DMMF.DatamodelEnum): string {
  const doc = dmmfEnum.documentation ? `/** ${dmmfEnum.documentation} */\n` : ''
  const values = dmmfEnum.values.map((v) => `'${v.name}'`).join(' | ')
  return `${doc}export type ${dmmfEnum.name} = ${values}`
}

/**
 * Renders a DMMF model as a TypeScript interface.
 * Scalar and enum fields are typed directly; relation fields are typed as optional
 * since REST responses may or may not include nested objects.
 */
export function renderModelInterface(model: DMMF.Model): string {
  const lines: string[] = []
  if (model.documentation) lines.push(`/** ${model.documentation} */`)
  lines.push(`export interface ${model.name} {`)
  for (const field of model.fields) {
    if (field.documentation) lines.push(`  /** ${field.documentation} */`)
    if (field.kind === 'object') {
      const base = field.isList ? `${field.type}[]` : field.type
      lines.push(`  ${field.name}?: ${base} | null`)
    } else {
      lines.push(`  ${field.name}: ${mapFieldToInterfaceType(field)}`)
    }
  }
  lines.push('}')
  return lines.join('\n')
}

/**
 * Renders the CreateInput type for a model.
 * Auto-generated, read-only, and `@updatedAt` fields are excluded.
 * Fields without defaults are required; others are optional.
 */
export function renderCreateInput(model: DMMF.Model): string {
  const lines: string[] = [`export interface ${model.name}CreateInput {`]
  for (const field of model.fields) {
    if (isExcludedFromCreate(field)) continue
    const type = mapFieldToInputType(field)
    const isOptional = !field.isRequired || field.hasDefaultValue
    const canBeNull = !field.isRequired
    const optMarker = isOptional ? '?' : ''
    const nullSuffix = canBeNull ? ' | null' : ''
    lines.push(`  ${field.name}${optMarker}: ${type}${nullSuffix}`)
  }
  lines.push('}')
  return lines.join('\n')
}

/**
 * Renders the UpdateInput type for a model.
 * All mutable, non-identity fields are optional to support partial updates.
 */
export function renderUpdateInput(model: DMMF.Model): string {
  const lines: string[] = [`export interface ${model.name}UpdateInput {`]
  for (const field of model.fields) {
    if (isExcludedFromUpdate(field)) continue
    const type = mapFieldToInputType(field)
    const canBeNull = !field.isRequired
    const nullSuffix = canBeNull ? ' | null' : ''
    lines.push(`  ${field.name}?: ${type}${nullSuffix}`)
  }
  lines.push('}')
  return lines.join('\n')
}

/** Renders the WhereUniqueInput type containing all `@id` and scalar `@unique` fields. */
export function renderWhereUniqueInput(model: DMMF.Model): string {
  const uniqueFields = model.fields.filter((f) => (f.isId || f.isUnique) && f.kind === 'scalar')
  const lines: string[] = [`export interface ${model.name}WhereUniqueInput {`]
  for (const field of uniqueFields) {
    lines.push(`  ${field.name}?: ${mapScalarType(field.type)}`)
  }
  lines.push('}')
  return lines.join('\n')
}

/**
 * Renders a REST client class for a single model with the five standard CRUD methods:
 * findMany, findUnique, create, update, and delete.
 *
 * Uses the native `fetch` API (Node.js 18+ / browser) with no additional dependencies.
 * Single-record operations derive the URL path segment from the model's `@id` field,
 * falling back to the first scalar `@unique` field.
 */
export function renderModelClient(model: DMMF.Model, pluralName: string, defaultBaseUrl: string): string {
  const m = model.name
  const route = pluralName.toLowerCase()
  const primaryField = findPrimaryField(model)

  const idExtract = primaryField
    ? `    const id = where.${primaryField.name}\n    if (id === undefined) throw new Error('${m}: a unique identifier is required')`
    : `    throw new Error('${m} has no @id or @unique field; single-record operations are not supported')`

  return [
    `export class ${m}RestClient {`,
    `  readonly #baseUrl: string`,
    ``,
    `  constructor(baseUrl: string = '${defaultBaseUrl}') {`,
    `    this.#baseUrl = baseUrl.endsWith('/') ? baseUrl.slice(0, -1) : baseUrl`,
    `  }`,
    ``,
    `  async findMany(params?: { skip?: number; take?: number }): Promise<${m}[]> {`,
    `    const url = new URL(\`\${this.#baseUrl}/${route}\`)`,
    `    if (params?.skip !== undefined) url.searchParams.set('skip', String(params.skip))`,
    `    if (params?.take !== undefined) url.searchParams.set('take', String(params.take))`,
    `    const response = await fetch(url.toString())`,
    `    if (!response.ok) throw new Error(\`HTTP \${response.status}: \${response.statusText}\`)`,
    `    return response.json() as Promise<${m}[]>`,
    `  }`,
    ``,
    `  async findUnique(where: ${m}WhereUniqueInput): Promise<${m} | null> {`,
    idExtract,
    `    const response = await fetch(\`\${this.#baseUrl}/${route}/\${id}\`)`,
    `    if (response.status === 404) return null`,
    `    if (!response.ok) throw new Error(\`HTTP \${response.status}: \${response.statusText}\`)`,
    `    return response.json() as Promise<${m}>`,
    `  }`,
    ``,
    `  async create(data: ${m}CreateInput): Promise<${m}> {`,
    `    const response = await fetch(\`\${this.#baseUrl}/${route}\`, {`,
    `      method: 'POST',`,
    `      headers: { 'Content-Type': 'application/json' },`,
    `      body: JSON.stringify(data),`,
    `    })`,
    `    if (!response.ok) throw new Error(\`HTTP \${response.status}: \${response.statusText}\`)`,
    `    return response.json() as Promise<${m}>`,
    `  }`,
    ``,
    `  async update(where: ${m}WhereUniqueInput, data: ${m}UpdateInput): Promise<${m}> {`,
    idExtract,
    `    const response = await fetch(\`\${this.#baseUrl}/${route}/\${id}\`, {`,
    `      method: 'PATCH',`,
    `      headers: { 'Content-Type': 'application/json' },`,
    `      body: JSON.stringify(data),`,
    `    })`,
    `    if (!response.ok) throw new Error(\`HTTP \${response.status}: \${response.statusText}\`)`,
    `    return response.json() as Promise<${m}>`,
    `  }`,
    ``,
    `  async delete(where: ${m}WhereUniqueInput): Promise<${m}> {`,
    idExtract,
    `    const response = await fetch(\`\${this.#baseUrl}/${route}/\${id}\`, {`,
    `      method: 'DELETE',`,
    `    })`,
    `    if (!response.ok) throw new Error(\`HTTP \${response.status}: \${response.statusText}\`)`,
    `    return response.json() as Promise<${m}>`,
    `  }`,
    `}`,
  ].join('\n')
}

/** Renders the root RestApiClient that instantiates and exposes all per-model clients. */
export function renderRootClient(models: readonly DMMF.Model[], defaultBaseUrl: string): string {
  const lines: string[] = ['export class RestApiClient {']
  for (const model of models) {
    const prop = model.name.charAt(0).toLowerCase() + model.name.slice(1)
    lines.push(`  readonly ${prop}: ${model.name}RestClient`)
  }
  lines.push('')
  lines.push(`  constructor(baseUrl: string = '${defaultBaseUrl}') {`)
  for (const model of models) {
    const prop = model.name.charAt(0).toLowerCase() + model.name.slice(1)
    lines.push(`    this.${prop} = new ${model.name}RestClient(baseUrl)`)
  }
  lines.push('  }')
  lines.push('}')
  return lines.join('\n')
}

/** Renders the complete REST client TypeScript source file from a DMMF document. */
export function renderFile(dmmf: DMMF.Document, defaultBaseUrl: string): string {
  const { models, enums } = dmmf.datamodel
  const pluralMap = new Map(dmmf.mappings.modelOperations.map((m) => [m.model, m.plural]))

  const parts: string[] = [
    '// This file was generated by @prisma/client-generator-rest-api',
    '// Do not edit manually -- regenerate by running `prisma generate`',
  ]

  if (enums.length > 0) {
    parts.push('')
    parts.push('// Enums')
    parts.push('')
    parts.push(enums.map(renderEnum).join('\n\n'))
  }

  if (models.length > 0) {
    parts.push('')
    parts.push('// Model interfaces')
    parts.push('')
    parts.push(models.map(renderModelInterface).join('\n\n'))

    parts.push('')
    parts.push('// Input types')
    parts.push('')
    parts.push(
      models
        .flatMap((model) => [renderCreateInput(model), renderUpdateInput(model), renderWhereUniqueInput(model)])
        .join('\n\n'),
    )

    parts.push('')
    parts.push('// Model REST clients')
    parts.push('')
    parts.push(
      models
        .map((model) => {
          const plural = pluralMap.get(model.name) ?? `${model.name.toLowerCase()}s`
          return renderModelClient(model, plural, defaultBaseUrl)
        })
        .join('\n\n'),
    )

    parts.push('')
    parts.push('// Root client')
    parts.push('')
    parts.push(renderRootClient(models, defaultBaseUrl))
  }

  return parts.join('\n') + '\n'
}

