import fs from 'node:fs/promises'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'

import { renderFile } from './rest-client-renderer'

export interface GenerateRestClientOptions {
  outputDir: string
  dmmf: DMMF.Document
  defaultBaseUrl: string
}

/**
 * Generates a typed REST API client TypeScript source file into `outputDir`.
 * Creates `outputDir` (recursively) if it does not already exist.
 */
export async function generateRestClient(options: GenerateRestClientOptions): Promise<void> {
  const { outputDir, dmmf, defaultBaseUrl } = options

  await fs.mkdir(outputDir, { recursive: true })

  const content = renderFile(dmmf, defaultBaseUrl)
  const outputPath = path.join(outputDir, 'rest-client.ts')

  await fs.writeFile(outputPath, content, 'utf-8')
}

