import type { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

import { version } from '../package.json'
import { generateRestClient } from './generate-rest-client'

const DEFAULT_BASE_URL = 'http://localhost:3000'

/** The provider name users specify in the `generator` block of their Prisma schema. */
export const PROVIDER_NAME = 'prisma-rest-api-client'

/** Resolves an EnvValue to its string value, reading from the environment when `fromEnvVar` is set. */
function resolveEnvValue(envValue: { fromEnvVar: string | null; value: string | null }): string {
  if (envValue.fromEnvVar !== null) {
    const resolved = process.env[envValue.fromEnvVar]
    if (resolved === undefined) {
      throw new Error(`Environment variable "${envValue.fromEnvVar}" is not set`)
    }
    return resolved
  }
  return envValue.value ?? ''
}

/**
 * Prisma generator that produces a typed REST API client from the schema's DMMF.
 *
 * Schema usage:
 * ```prisma
 * generator restApi {
 *   provider = "prisma-rest-api-client"
 *   output   = "./generated/rest-api"
 *   // Optional: default base URL embedded in the generated client
 *   baseUrl  = "https://api.example.com"
 * }
 * ```
 *
 * Output: a single `rest-client.ts` file in the specified `output` directory containing
 * TypeScript interfaces for every model, typed input/output types, per-model CRUD client
 * classes, and a root `RestApiClient` that aggregates them all.
 */
export class RestApiGenerator implements Generator {
  readonly name = PROVIDER_NAME

  async getManifest(_config: GeneratorConfig): Promise<GeneratorManifest> {
    return {
      prettyName: 'REST API Client',
      defaultOutput: './generated/rest-api',
      version,
    }
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const { output } = options.generator
    if (!output) {
      throw new Error(
        'The REST API generator requires an `output` path in your Prisma schema generator block.\n' +
          'Example: output = "./generated/rest-api"',
      )
    }

    const outputDir = resolveEnvValue(output)

    const baseUrlConfig = options.generator.config.baseUrl
    const defaultBaseUrl = typeof baseUrlConfig === 'string' ? baseUrlConfig : DEFAULT_BASE_URL

    await generateRestClient({
      outputDir,
      dmmf: options.dmmf,
      defaultBaseUrl,
    })
  }
}

